  // ===== OFF-META & FLEX PICKS =====
  akshan: {"diff":"TRICKY","tone":"#ff8b3d","tldr":"Weather the poke — wall-stun him on the Heroic Swing cooldown — your W deletes dashes.","breakdown":"Akshan plays around Heroic Swing. Pin him to terrain with E when Heroic Swing is down, Q the slow zone, and your W turns every dash he owns into wasted mana. Doran’s Shield blunts the poke war.","dos":["E wall-stun when Heroic Swing is down","W his dash mid-flight","Q-zone his farm"],"donts":["E with no wall behind","Waste W early","Eat poke at range"],"key":{"slot":"E","name":"Heroic Swing","cd":"14s","note":"His dash + camera swing escape. Engage when it's down.","winT":"SWING DOWN","winS":"E wall-stun + Q burst."},"win":"Wall-stun him on the Heroic Swing cooldown — your W deletes dashes."},
